def parse_bearer_token(auth_header: str):
    if not auth_header:
        return None
    parts = auth_header.split(None, 1)
    if len(parts) != 2:
        return None
    scheme, value = parts[0].strip(), parts[1].strip()
    if scheme.lower() != "bearer" or not value:
        return None
    return value


def normalize_scopes(scope_str: str):
    if not scope_str:
        return set()
    return {s for s in scope_str.split() if s}


